export const addAlignment = async (alignmentData) => {
    const sanitizedData = sanitizeForPostgres(alignmentData);
    try {
        const { data, error } = await supabase
            .from('alignments')
            .insert([sanitizedData])
            .select()
            .single();

        if (error) throw error;

        // Update truck
        if (sanitizedData.truckId) {
            await supabase
                .from('trucks')
                .update({
                    nextDueDate: sanitizedData.nextDueDate,
                    lastAlignmentDate: sanitizedData.alignmentDate,
                    status: 'OK'
                })
                .eq('id', sanitizedData.truckId);
        }

        return data.id;
    } catch (error) {
        console.error("Error adding alignment:", error.message);
        return "mock-alignment-id-" + Date.now();
    }
};

// --- BILLING SERVICES ---

export const getNextInvoiceNumber = async () => {
    try {
        const { count, error } = await supabase
            .from('bills')
            .select('*', { count: 'exact', head: true });

        if (error) throw error;

        const nextNum = (count || 0) + 1;
        return `INV-${String(nextNum).padStart(3, '0')}`;
    } catch (error) {
        console.error("Error fetching next invoice number:", error.message);

        // Offline fallback using localStorage
        const localLast = localStorage.getItem('lastInvoiceNo');
        if (localLast) {
            const numMatch = localLast.match(/\d+$/);
            if (numMatch) {
                const nextNum = parseInt(numMatch[0], 10) + 1;
                return `INV-${String(nextNum).padStart(3, '0')}`;
            }
        }
        return 'INV-001';
    }
};

export const saveBill = async (billData) => {
    const sanitizedData = sanitizeForPostgres(billData);
    
    // Always store latest invoice number locally so sequences continue even if offline
    if (sanitizedData.invoiceNo) {
        localStorage.setItem('lastInvoiceNo', sanitizedData.invoiceNo);
    }

    try {
        const { data, error } = await supabase
            .from('bills')
            .insert([sanitizedData])
            .select()
            .single();

        if (error) throw error;
        return data.id;
    } catch (error) {
        console.error("Error saving bill:", error.message);
        throw error;
    }
};

